}

/// Single renderer for ALL strategies
#[component]
pub fn VirtualTable<T, D>(
    data_source: D,
    render_row: impl Fn(T) -> View + 'static,
) -> impl IntoView 
where
    D: DataSource<T>
{
    // Viewport calculation
    // Row rendering
    // Scroll handling
    // SAME for all strategies
}
