struct MoveItemCommand {
    item_id: String,
    from: Position,
    to: Position,
}

impl Command for MoveItemCommand {
    fn execute(&self) { /* move item */ }
    fn undo(&self) { /* restore position */ }
}

command_history.push(command);
```

