```rust
struct MacroCommand {
    commands: Vec<Box<dyn Command>>,
    description: String,
}

impl Command for MacroCommand {
    fn execute(&self, state: &mut AppState) {
        for cmd in &self.commands {
            cmd.execute(state);
        }
    }

    fn undo(&self, state: &mut AppState) {
        for cmd in self.commands.iter().rev() {
            cmd.undo(state);
        }
    }
}

