## Lazy Loading Islands
```rust
// Host lazy-loads island
#[component]
fn DocsPage() -> impl IntoView {
    let load_island = create_action(|_| async {
        // Dynamic import
        let module = js_sys::eval(
            r#"import("/islands/markdown/markdown.js")"#
        ).await;
